BEGIN TRANSACTION;
CREATE TABLE "dim_customer" (
"customer_code" INTEGER,
  "customer_name" TEXT
);
CREATE TABLE "dim_product" (
"product_code" INTEGER,
  "product_name" TEXT,
  "brand_name" TEXT,
  "department" TEXT,
  "sub_category" TEXT
);
CREATE TABLE "dim_store" (
"store_name" TEXT,
  "region" TEXT,
  "store_code" INTEGER
);
CREATE TABLE "fact_gross_price" (
"product_code" INTEGER,
  "fiscal_year" REAL,
  "gross_price" REAL
);
CREATE TABLE "fact_inventory" (
"product_code" INTEGER,
  "batch" TEXT,
  "mrp" REAL,
  "expiry_date" TEXT,
  "quantity" REAL
);
CREATE TABLE "fact_sales" (
"bill_date" TIMESTAMP,
  "bill_number" TEXT,
  "customer_code" INTEGER,
  "product_code" INTEGER,
  "quantity" REAL,
  "mrp" REAL,
  "amount" REAL,
  "base_value" REAL,
  "sgst" REAL,
  "cgst" REAL,
  "total_disc_amount" REAL,
  "disc_pct" REAL,
  "fiscal_year" REAL,
  "quarter" TEXT,
  "store_code" INTEGER
);
COMMIT;
